{
  "grammar": [
    {
      "pattern": "一 + measure word + noun",
      "structure": ["number", "measure word", "noun"],
      "explanation_en": "Use measure words between numbers and nouns. Common ones: 個 (general), 杯 (drinks), 本 (books), 張 (flat objects), 瓶 (bottles), 包 (packages).",
      "title": "Basic Measure Words",
      "meaning": "Use measure words to count items.",
      "when_to_use": ["When ordering items in a store", "When asking for quantity", "When describing items"],
      "when_not_to_use": ["With abstract nouns like 問題", "When the noun already implies a unit"],
      "pragmatic_notes": "In Taiwan, 一個 is very common for general items. For drinks, always use 杯. For flat items like receipts, use 張.",
      "word_order_notes": "Number + measure word + noun. Example: 一杯咖啡, 兩張收據.",
      "english_contrast": "English doesn't use measure words; 'a coffee' vs '一杯咖啡'.",
      "korean_contrast": "Korean uses counters like '한 잔' (one cup) similar to Chinese '一杯'.",
      "negative_examples": [
        {
          "text": "我要一咖啡。",
          "error": "Missing measure word 杯."
        },
        {
          "text": "我要兩收據。",
          "error": "Missing measure word 張."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我要一咖啡。",
          "error": "Missing measure word 杯."
        },
        {
          "text": "我要兩收據。",
          "error": "Missing measure word 張."
        }
      ],
      "transformation_drills": ["Change '一咖啡' to '一杯咖啡'", "Change '兩收據' to '兩張收據'"],
      "production_drills": ["Order a bottle of water", "Ask for two receipts"],
      "common_error_patterns": ["Omitting measure words", "Using wrong measure word"],
      "repair_feedback": {
        "word_order": "Remember: number + measure word + noun.",
        "politeness": "Add 請 or 不好意思 for politeness.",
        "vocabulary": "Use correct measure word: 杯 for drinks, 張 for flat items."
      }
    },
    {
      "pattern": "要 + noun + 嗎？ / 要不要 + noun？",
      "structure": ["要", "noun", "嗎"],
      "explanation_en": "Use 要不要 or 要...嗎 to ask if someone wants something. 要不要 is more casual, 要...嗎 is neutral.",
      "title": "Asking 'Want or Not'",
      "meaning": "Ask if someone wants an item.",
      "when_to_use": ["When a store clerk asks if you want a bag", "When offering something to a friend", "When confirming an order"],
      "when_not_to_use": ["For polite requests (use 請 or 不好意思)", "When asking about ability (use 可以)"],
      "pragmatic_notes": "In Taiwan, store clerks often ask '要不要袋子？' or '要袋子嗎？'. Answer with '要' (yes) or '不要' (no).",
      "word_order_notes": "Subject + 要不要 + noun? or Subject + 要 + noun + 嗎?",
      "english_contrast": "English uses 'Do you want...?' while Chinese uses 要不要 or 要...嗎.",
      "korean_contrast": "Korean uses '원하세요?' similar to 要...嗎.",
      "negative_examples": [
        {
          "text": "你要袋子不要？",
          "error": "Incorrect structure; use 要不要袋子？ or 要袋子嗎？"
        },
        {
          "text": "你要不要？袋子。",
          "error": "Noun should be before 嗎 or after 要不要."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你要袋子不要？",
          "error": "Incorrect structure; use 要不要袋子？ or 要袋子嗎？"
        },
        {
          "text": "你要不要？袋子。",
          "error": "Noun should be before 嗎 or after 要不要."
        }
      ],
      "transformation_drills": ["Change '要袋子嗎？' to '要不要袋子？'", "Change '要不要收據？' to '要收據嗎？'"],
      "production_drills": ["Ask if a friend wants coffee", "Ask a clerk if you need a receipt"],
      "common_error_patterns": ["Using 要不要 with 嗎 together", "Placing noun after 嗎"],
      "repair_feedback": {
        "word_order": "Use 要不要 + noun or 要 + noun + 嗎.",
        "politeness": "Add 請 for polite offers.",
        "vocabulary": "Use 要 for wanting, not 想."
      }
    },
    {
      "pattern": "這個 / 那個 + noun",
      "structure": ["這個/那個", "noun"],
      "explanation_en": "Use 這個 (this) for items near you, 那個 (that) for items far from you. Can be used alone or with a noun.",
      "title": "This and That Review",
      "meaning": "Point to items using 這個 and 那個.",
      "when_to_use": ["When pointing to items in a store", "When choosing between two items", "When asking about a specific item"],
      "when_not_to_use": ["For people (use 這位/那位)", "For abstract concepts"],
      "pragmatic_notes": "In Taiwan convenience stores, point and say '這個' or '那個' to indicate items. It's common and polite.",
      "word_order_notes": "這個/那個 + noun. Example: 這個便當, 那個飯糰.",
      "english_contrast": "English uses 'this' and 'that' similarly, but Chinese doesn't change form for plural.",
      "korean_contrast": "Korean uses '이것' (this) and '그것' (that) similarly.",
      "negative_examples": [
        {
          "text": "我要這個的便當。",
          "error": "No need for 的; use 這個便當."
        },
        {
          "text": "那個是飯糰。",
          "error": "Correct, but if pointing, just say 那個飯糰."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我要這個的便當。",
          "error": "No need for 的; use 這個便當."
        },
        {
          "text": "那個是飯糰。",
          "error": "Correct, but if pointing, just say 那個飯糰."
        }
      ],
      "transformation_drills": ["Change '這個是便當' to '這個便當'", "Change '那個是水' to '那個水'"],
      "production_drills": ["Point to a tea egg and say 'that tea egg'", "Point to a sandwich and say 'this sandwich'"],
      "common_error_patterns": ["Adding 的 between 這個/那個 and noun", "Using 這個 for far items"],
      "repair_feedback": {
        "word_order": "Use 這個/那個 directly before noun.",
        "politeness": "Pointing is fine, but add 不好意思 for attention.",
        "vocabulary": "Use 這個 for near, 那個 for far."
      }
    }
  ]
}
